/**
 * Corgi Dashboard — Canvas/HTML Preview Panel
 *
 * Renders HTML content in a sandboxed iframe with optional script
 * execution toggle, refresh, and screenshot capture.
 */
import React, { useCallback, useRef, useState } from 'react';
import { RefreshCw, Camera, Shield, ShieldOff } from 'lucide-react';
import { SidePanel } from './SidePanel';
import { useContentPanel, type CanvasContent } from './ContentPanelManager';

/* ------------------------------------------------------------------ */
/*  Component                                                          */
/* ------------------------------------------------------------------ */

export const CanvasPanel: React.FC = () => {
  const { panelType, panelContent, closePanel } = useContentPanel();
  const iframeRef = useRef<HTMLIFrameElement>(null);
  const [allowScripts, setAllowScripts] = useState(false);
  const [refreshKey, setRefreshKey] = useState(0);

  const handleRefresh = useCallback(() => {
    setRefreshKey((k) => k + 1);
  }, []);

  const toggleScripts = useCallback(() => {
    setAllowScripts((prev) => !prev);
    // Refresh when toggling scripts to re-render with new sandbox policy
    setRefreshKey((k) => k + 1);
  }, []);

  const handleScreenshot = useCallback(async () => {
    // Attempt to capture iframe content as data URL
    // Note: this only works for same-origin or srcdoc content
    try {
      const iframe = iframeRef.current;
      if (!iframe?.contentDocument) {
        console.warn('Cannot capture screenshot: cross-origin or unavailable');
        return;
      }

      const canvas = document.createElement('canvas');
      const body = iframe.contentDocument.body;
      canvas.width = body.scrollWidth;
      canvas.height = body.scrollHeight;

      // Use html2canvas-like approach via serialisation
      const svgData = `
        <svg xmlns="http://www.w3.org/2000/svg" width="${canvas.width}" height="${canvas.height}">
          <foreignObject width="100%" height="100%">
            <div xmlns="http://www.w3.org/1999/xhtml">
              ${body.innerHTML}
            </div>
          </foreignObject>
        </svg>
      `;

      const svgBlob = new Blob([svgData], { type: 'image/svg+xml;charset=utf-8' });
      const url = URL.createObjectURL(svgBlob);

      const img = new Image();
      img.onload = () => {
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(img, 0, 0);
        URL.revokeObjectURL(url);

        // Download the screenshot
        const dataUrl = canvas.toDataURL('image/png');
        const a = document.createElement('a');
        a.href = dataUrl;
        a.download = 'canvas-screenshot.png';
        document.body.appendChild(a);
        a.click();
        document.body.removeChild(a);
      };
      img.src = url;
    } catch {
      console.warn('Screenshot capture failed');
    }
  }, []);

  if (panelType !== 'canvas') return null;

  const content = panelContent as CanvasContent | null;
  if (!content) return null;

  // Use content's allowScripts preference as initial, but let user toggle
  const scriptsEnabled = allowScripts || content.allowScripts;

  const sandboxValue = scriptsEnabled
    ? 'allow-scripts allow-modals'
    : '';

  const headerActions = (
    <div className="flex items-center gap-1">
      <CanvasButton
        onClick={toggleScripts}
        title={scriptsEnabled ? 'Disable scripts (sandboxed)' : 'Enable scripts'}
      >
        {scriptsEnabled ? <ShieldOff size={14} /> : <Shield size={14} />}
      </CanvasButton>
      <CanvasButton onClick={handleScreenshot} title="Screenshot">
        <Camera size={14} />
      </CanvasButton>
      <CanvasButton onClick={handleRefresh} title="Refresh">
        <RefreshCw size={14} />
      </CanvasButton>
    </div>
  );

  return (
    <SidePanel
      open
      onClose={closePanel}
      title={content.title ?? 'Canvas Preview'}
      headerActions={headerActions}
      defaultWidth={0.45}
    >
      {/* Script warning banner */}
      {scriptsEnabled && (
        <div
          className="flex items-center gap-2 mb-3 px-3 py-2 rounded-md"
          style={{
            background: 'color-mix(in srgb, var(--warning) 15%, transparent)',
            border: '1px solid color-mix(in srgb, var(--warning) 30%, transparent)',
            fontSize: 'var(--text-xs)',
            color: 'var(--warning, #FFB800)',
          }}
        >
          <ShieldOff size={12} />
          Scripts enabled — content executes in sandboxed iframe
        </div>
      )}

      {/* Iframe */}
      <div
        style={{
          width: '100%',
          height: '100%',
          minHeight: 400,
          borderRadius: 'var(--radius-md)',
          overflow: 'hidden',
          border: '1px solid var(--border-subtle)',
          background: '#ffffff',
        }}
      >
        <iframe
          ref={iframeRef}
          key={refreshKey}
          srcDoc={content.html}
          sandbox={sandboxValue}
          title={content.title ?? 'Canvas Preview'}
          style={{
            width: '100%',
            height: '100%',
            minHeight: 400,
            border: 'none',
            display: 'block',
          }}
        />
      </div>
    </SidePanel>
  );
};

/* ------------------------------------------------------------------ */
/*  Canvas Toolbar Button                                              */
/* ------------------------------------------------------------------ */

const CanvasButton: React.FC<{
  onClick: () => void;
  title: string;
  children: React.ReactNode;
}> = ({ onClick, title, children }) => (
  <button
    onClick={onClick}
    title={title}
    className="p-1.5 rounded-md transition-colors"
    style={{
      color: 'var(--text-muted)',
      background: 'transparent',
      border: 'none',
      cursor: 'pointer',
      display: 'flex',
      alignItems: 'center',
    }}
    onMouseEnter={(e) => {
      (e.currentTarget as HTMLElement).style.background = 'var(--bg-tertiary)';
      (e.currentTarget as HTMLElement).style.color = 'var(--text-primary)';
    }}
    onMouseLeave={(e) => {
      (e.currentTarget as HTMLElement).style.background = 'transparent';
      (e.currentTarget as HTMLElement).style.color = 'var(--text-muted)';
    }}
  >
    {children}
  </button>
);

export default CanvasPanel;
